\begin{align*}
\text{gcd}\,(n^3 + 9, n+2) &= \text{gcd}\,(n^3 + 9 - (n^3 + 8), n+2) \\ 
& = \text{gcd}\,(1,n+2) \\
& = \boxed{1}.
\end{align*}

